-- ============================================================================
-- SCRIPT 6: EXPORT RESULTS FOR STATISTICAL TESTING & VISUALIZATION
-- ============================================================================

-- 1. Export Strict L7 Results for Python Statistical Testing
\COPY (WITH user_first_events AS (SELECT u.user_id, u."group", MIN(e.event_date) as first_event_date FROM users u LEFT JOIN events e ON u.user_id = e.user_id GROUP BY u.user_id, u."group"), l7_check AS (SELECT ufe.user_id, ufe."group", MAX(CASE WHEN e.event_date = ufe.first_event_date + INTERVAL '7 days' THEN 1 ELSE 0 END) as returned FROM user_first_events ufe LEFT JOIN events e ON ufe.user_id = e.user_id GROUP BY ufe.user_id, ufe."group") SELECT "group", COUNT(*) as cohort_size, SUM(returned) as returned_count FROM l7_check GROUP BY "group") TO '/Users/emily/Downloads/ai-chat-retention-analysis/data/l7_retention_results.csv' WITH CSV HEADER;

-- 2. Export Strict L28 Results for Python Statistical Testing
\COPY (WITH user_first_events AS (SELECT u.user_id, u."group", MIN(e.event_date) as first_event_date FROM users u LEFT JOIN events e ON u.user_id = e.user_id GROUP BY u.user_id, u."group"), l28_check AS (SELECT ufe.user_id, ufe."group", MAX(CASE WHEN e.event_date = ufe.first_event_date + INTERVAL '28 days' THEN 1 ELSE 0 END) as returned FROM user_first_events ufe LEFT JOIN events e ON ufe.user_id = e.user_id GROUP BY ufe.user_id, ufe."group") SELECT "group", COUNT(*) as cohort_size, SUM(returned) as returned_count FROM l28_check GROUP BY "group") TO '/Users/emily/Downloads/ai-chat-retention-analysis/data/l28_retention_results.csv' WITH CSV HEADER;

-- 3. Export Daily Retention Curve for Tableau/Excel Dashboards
\COPY (WITH user_first_events AS (SELECT u.user_id, u."group", MIN(e.event_date) as first_event_date FROM users u LEFT JOIN events e ON u.user_id = e.user_id GROUP BY u.user_id, u."group"), retention_by_day AS (SELECT ufe."group", (e.event_date - ufe.first_event_date) + 1 as day_number, COUNT(DISTINCT ufe.user_id) as users_active FROM user_first_events ufe LEFT JOIN events e ON ufe.user_id = e.user_id WHERE e.event_date >= ufe.first_event_date GROUP BY ufe."group", day_number), cohort_sizes AS (SELECT "group", COUNT(*) as total_users FROM users GROUP BY "group") SELECT r."group", r.day_number, r.users_active, c.total_users as cohort_size, ROUND(100.0 * r.users_active / c.total_users, 2) as retention_pct FROM retention_by_day r JOIN cohort_sizes c ON r."group" = c."group" WHERE r.day_number BETWEEN 1 AND 30 ORDER BY r."group", r.day_number) TO '/Users/emily/Downloads/ai-chat-retention-analysis/data/retention_curve.csv' WITH CSV HEADER;